#include <vector>

using namespace std;

int find_nth_number(int n) {
    // 초기 조건
    if (n == 0) return 0;
    if (n == 1) return -1;
    if (n == 2) return -1;

    vector<int> sequence = {0, -1, -1}; // 초기 세 숫자

    // n이 3 이상일 때, 수열을 확장
